"use strict";const test=require("tape"),fastURI=require("..");test("parse preserves reserved path escapes as data",e=>{const a=fastURI.parse("http://example.com/a%2Fb/public/%2e%2e/admin");e.equal(a.path,"/a%2Fb/public/%2E%2E/admin"),e.end()}),test("normalize preserves percent-encoded path separators and dot segments",e=>{e.equal(fastURI.normalize("http://example.com/public/%2e%2e/admin"),"http://example.com/public/%2E%2E/admin"),e.equal(fastURI.normalize("http://example.com/a%2Fb"),"http://example.com/a%2Fb"),e.end()}),test("equal does not treat reserved path escapes as live path syntax",e=>{e.equal(fastURI.equal("http://example.com/public/%2e%2e/admin","http://example.com/admin",{}),!1),e.equal(fastURI.equal("http://example.com/a%2Fb","http://example.com/a/b",{}),!1),e.end()});